```latex
void insert(list_pointer *ptr, list_pointer node)
{
    /* insert a new node with data = 50 into the list ptr after node */
    list_pointer temp;
    temp = (list_pointer)malloc(sizeof(list_node));
    if (IS_FULL(temp)) {
        fprintf(stderr, "The memory is full\\n");
        exit(1);
    }
    temp->data = 50;
    if (*ptr) {
        temp->link = node->link;
        node->link = temp;
    } else {
        temp->link = NULL;
        *ptr = temp;
    }
}

