void cerase(poly_pointer *ptr)
{
  /* erase the circular list ptr */
  poly_pointer temp;
  if (*ptr) {
    temp = (*ptr)->link;
    (*ptr)->link = avail;
    avail = temp;
    *ptr = NULL;
  }
}
\\end{verbatim}

