#define MAX_SIZE 50 /*size of largest matrix*/
typedef enum {head,entry} tagfield;
typedef struct entry_node {
    int row;
    int col;
    int value;
};
typedef struct matrix_node {
    matrix_pointer down;
    matrix_pointer right;
    tagfield tag;
    union {
        matrix_pointer next;
        entry_node entry;
    } u;
};
matrix_pointer hdnode[MAX_SIZE];
\\end{verbatim}

\\begin{verbatim}
node->u.entry.row = num_rows;
node->u.entry.col = num_cols;

if (!num_heads) node->right = node;
else { /* initialize the head nodes */
    for (i = 0; i < num_heads; i++) {
        temp = new_node();
        hdnode[i] = temp;
        hdnode[i]->tag = head;
        hdnode[i]->right = temp;
        hdnode[i]->u.next = temp;
    }
    current_row = 0;
    last = hdnode[0]; /* last node in current row */
    for (i = 0; i < num_terms; i++) {
        printf("Enter row, column and value: ");
        scanf("%d%d%d",&row,&col,&value);
        if (row > current_row) { /* close current row */
            last->right = hdnode[current_row];
            current_row = row;
            last = hdnode[row];
            temp = new_node();
            temp->tag = entry;
            temp->u.entry.row = row;
            temp->u.entry.col = col;
            temp->u.entry.value = value;
            last->right = temp; /* link into row list */
            last = temp;
            /* link into column list */
            hdnode[col]->u.next->down = temp;
            hdnode[col]->u.next = temp;
        }
    }
    /* close last row */
    last->right = hdnode[current_row];
    /* close all column lists */
    for (i = 0; i < num_cols; i++)
        hdnode[i]->u.next->down = hdnode[i];
    /* link all head nodes together */
    for (i = 0; i < num_heads-1; i++)
        hdnode[i]->u.next = hdnode[i+1];
    hdnode[num_heads-1]->u.next = node;
    node->right = hdnode[0];
}
return node;
\\end{verbatim}

