void ddelete(node_pointer node, node_pointer deleted)
{
    /* delete from the doubly linked list */
    if (node == deleted)
        printf("Deletion of head node not permitted.\\n");
    else {
        deleted->llink->rlink = deleted->rlink;
        deleted->rlink->llink = deleted->llink;
        free(deleted);
    }
}
\\end{verbatim}

