\\begin{verbatim}
void union2(int i, int j)
/* union the sets with roots i and j, i != j, using the weighting rule. parent[i] = -count[i] and parent[j] = -count[j] */
int temp = parent[i] + parent[j];
if (parent[i] > parent[j]) {
    parent[i] = j; /* make j the new root */
    parent[j] = temp;
} else {
    parent[j] = i; /* make i the new root */
    parent[i] = temp;
}
\\end{verbatim}

