\\begin{verbatim}
void verify_max(element heap[], int i, element item)
{
    /* follow the nodes from the max node i to the root and insert item into its proper place */
    int grandparent = i/4;
    while (grandparent) {
        if (item.key > heap[grandparent].key) {
            heap[i] = heap[grandparent];
            i = grandparent;
            grandparent /= 4;
        }
        else break;
    }
    heap[i] = item;
}
\\end{verbatim}

