void avl_insert(tree_pointer *parent, element x, int *unbalanced)
{
    if (!*parent) {
        /* insert element into null tree */
        *unbalanced = TRUE;
        *parent = (tree_pointer) malloc(sizeof(tree_node));
        if (IS_FULL(*parent)) {
            fprintf(stderr, "The memory is full\\n");
            exit(1);
