78     if (i == hash_value) {
79         fprintf(stderr,"The Table is full \\n");
80         exit(1);
81     }
82 }
83 ht[i] = item;
84 }

85 int linear_search(element item, element ht[]) /*int linear_search(item, ht)*/
86 {
87     /* search for the key contained in item, return -1 if the key is not
88     in the table, and the position (j), if it is. */
89     int j, hash_value;
90     hash_value = hash(item.key);
91     j = hash_value;
92     for (;;) {
93         if (!strlen(ht[j].key))
94             return -1;
95         if (!strcmp(ht[j].key,item.key))
96             return j;
97         j = (j+1) % TABLE_SIZE;
98         if (j == hash_value)
99             return -1;
100     }
101 }

102 void init_table(element ht[])
103 {
104     int i;
105     for (i = 0; i < TABLE_SIZE; i++)
106         ht[i].key = NULL;
107 }
\\end{verbatim}

